export interface IdentifiableMixinProperties {}

/**
 * Mixin that adds a unique identifier property to instances.
 *
 * @since 4.0
 */
export abstract class IdentifiableMixin {
  constructor(...args: any[]);
  /**
   * An automatically generated unique identifier assigned to the instance. The unique id is generated each
   * time the application is loaded.
   *
   * @since 4.33
   */
  readonly uid: string;
}